#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<typename T>
void convert_from_big_endian_inplace(T& value) {
    if (std::endian::native != std::endian::big) {
        hexi::endian::be_inplace(value);
    }
}

template<typename T>
void convert_from_little_endian_inplace(T& value) {
    if (std::endian::native != std::endian::little) {
        hexi::endian::le_inplace(value);
    }
}

template<std::endian from, std::endian to, typename T>
void convert_endianness_inplace(T& value) {
    if (from != to) {
        if (from == std::endian::big && to == std::endian::little) {
            hexi::endian::b_to_l_inplace(value);
        } else if (from == std::endian::little && to == std::endian::big) {
            hexi::endian::l_to_b_inplace(value);
        } else {
            // Conditional approach for other cases
            if (from != std::endian::native) {
                if constexpr (from == std::endian::big) {
                    hexi::endian::be_inplace(value);
                } else {
                    hexi::endian::le_inplace(value);
                }
            }
            if (to != std::endian::native) {
                if constexpr (to == std::endian::big) {
                    hexi::endian::be_inplace(value);
                } else {
                    hexi::endian::le_inplace(value);
                }
            }
        }
    }
}
```

