template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Get readable data size using size() method
    status.readable_size = storage.size();

    // Calculate free space as total buffer size minus readable data size
    status.free_space = 1024 - status.readable_size; // Fixed block_size of 1024

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use clear() method to reset both read and write offsets to zero
    storage.clear();
}

