std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor and write data
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>, false> write_adaptor(buffer);

    // Check available space before writing
    if (write_adaptor.free() < input_data.size()) {
        // Resize buffer if needed
        buffer.resize(input_data.size() + 100); // Add some extra space
        write_adaptor = hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>, false>(buffer);
    }

    // Write data to buffer
    write_adaptor.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor to read data back
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>, false> read_adaptor(buffer);

    // Check readable size
    if (read_adaptor.size() < input_data.size()) {
        // Handle error - should not happen if we wrote successfully
        return {};
    }

    // Read data back
    std::vector<uint8_t> output_data(input_data.size());
    read_adaptor.read(output_data.data(), output_data.size());

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>, false> adaptor(buffer_data);

    // Use read_ptr() to get pointer to current read position
    const uint8_t* read_pointer = adaptor.read_ptr();

    // Use copy() to peek at data without moving read cursor
    std::vector<uint8_t> peeked_data(peek_size);
    adaptor.copy(peeked_data.data(), peek_size);

